#include<bits/stdc++.h>
using namespace std;
int d[30005];
int dis[30005];
int l[30005];
int find(int x) {
	if (d[x] == x) {
		return x;
	} else {
		int t=find(d[x]);
        dis[x]+=dis[d[x]];
        d[x]=t;
        return t;
    }
}
void up(int x, int y) {
	int fx = find(x);
	int fy = find(y);
    d[fx]=fy;
    dis[fx]+=l[fy];
    l[fy]+=l[fx];
}
int main() {
	int n;
	cin >> n ;
	for (int i = 1; i <= 30000; i++) {
        d[i] = i;
        l[i] = 1;
	}
	for (int i = 1; i <= n; i++) {
		int x, y;
        char z; 
		cin >> z;
       cin >> x;
        cin >> y;
		if (z == 'M') {
			up(x, y);
		} else {
			if (find(x) == find(y)) {
				cout << abs(dis[x]-dis[y])-1 << "\n";
			} else {
				cout << "-1" << "\n";
			}
		}
	}
	return 0;
}
